var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"라이트닝! 익스큐션───!","JPN":"ライトニング！　エクスキュージョン───！","ENG":"Lightning! Execution ──!","TWN":"雷光！處刑───！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"호오, 버러지 같은 필멸자 주제에 제법 발버둥 치는구나.","JPN":"ほう、虫けら同然の定命の者にしては随分と耐えるな。","ENG":"Oh? Struggling quite a bit for a lowly mortal, aren't you?","TWN":"喔，像蟲子一樣的凡人，居然還掙扎得挺厲害的嘛。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_02"},{"id":"L6_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"하지만 그 또한 부질없는 발악일지니.","JPN":"しかしそれもまた、無駄な足掻きにすぎん。","ENG":"But it's all just meaningless resistance.","TWN":"但那也不過是徒勞的掙扎罷了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"일어나거라, 왕의 자매들이여!","JPN":"立ち上がるのだ、王の姉妹たちよ！","ENG":"Get up, sisters of the Queen!","TWN":"起來吧，王的姊妹們！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"크윽! 역시 그림자를 부리는 능력이 성가시군!","JPN":"くっ！　やはりシャドウを操る能力が厄介だな！","ENG":"Tch... Controlling Shadows really is a damn nuisance!","TWN":"呃！果然操縱暗影的能力很棘手！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"망설일 시간이 없어… 거리를 좁히지 않으면 이쪽이 불리해……!","JPN":"迷っている場合じゃない……距離を縮めなければ、こっちが不利だ……！","ENG":"No time to hesitate... If we don't close the distance, we're at a serious disadvantage...!","TWN":"沒有時間猶豫了……如果不拉近距離，我們這邊會很不利……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COMPANY_MAIN_NPC_CAP","text":{"KOREA":"전 대원! 사도의 그림자를 집중 타격한다!","JPN":"総員！　使徒のシャドウに攻撃を集中しろ！","ENG":"All units, focus fire on the Apostle's Shadows!","TWN":"全體隊員！集中攻擊使徒的暗影！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMPANY_MAIN_NPC_CAP","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_EXPLOSION_FIRE_BIG"},{"id":"L18_1","type":"dialog","speaker":"COMPANY_MAIN_NPC_CAP","text":{"KOREA":"대령님께서 사도에게 가까이 접근할 수 있도록, 전력으로 지원하는 거다!","JPN":"大佐が使徒に近づけるよう、全力でサポートするんだ！","ENG":"Give the Colonel everything you've got and clear a path to the Apostle!","TWN":"全力支援，讓大人能夠接近使徒！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMPANY_MAIN_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"좋아, 지금이에요! 아키! 제가 길을 열게요!","JPN":"よし、今です、秋！　道を開けますね！","ENG":"Now's our chance! Aki! I'll clear the path!","TWN":"好了，就是現在！廣瀨秋！我來開路！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L23_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"하아아아아아아앗…!! 버스터……!!","JPN":"はあああああああ……！！　バスター……！！","ENG":"Haaaaaah! Buster!","TWN":"哈啊啊啊啊啊啊啊……！！破壞者……！！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"불경하구나, 필멸자여.","JPN":"不敬なり、定命の者よ。","ENG":"Insolent mortal.","TWN":"這是不敬，必滅者。"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"그런 허술한 공격이 이 몸에게 닿을 것 같으냐!","JPN":"そのような拙い攻撃が、余に届くはずがなかろう！","ENG":"You think such a feeble strike could reach me?","TWN":"這種拙劣的攻擊能打到我嗎！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"그래? 그럼, 이건 어때……!?","JPN":"そう？　じゃあ、これはどう……！？","ENG":"Oh yeah? Then how about this...?","TWN":"是嗎？那這個呢……！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"후후, 기습을 노리고 있다는 건 알고 있었다.","JPN":"ふふ、奇襲を狙っていたのは知っていた。","ENG":"Haha, I knew you were aiming for an ambush.","TWN":"呵呵，我早就知道你在伺機偷襲。"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"하지만 이미 말하지 않았느냐? 전부 부질없는 발악이라고.","JPN":"しかし言ったであろう。全ては無駄な足掻きだと。","ENG":"But haven't I told you already? It's all just meaningless resistance.","TWN":"但是我不是已經說過了嗎？這一切都是徒勞的掙扎。"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"이 몸과 정면으로 검을 맞부딪친 시점에서 네놈의 패배이니라.","JPN":"余と正面から剣を交えた時点で、貴様の負けだ。","ENG":"The moment you crossed blades with me head-on, your defeat was sealed.","TWN":"從你正面迎上我的劍的那一刻起，你就已經輸了。"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"크윽…! 칼 싸움 같은 건 아무래도 좋거든……!","JPN":"くっ……！　剣の腕なんてどうでもいい……！","ENG":"Ugh...! I couldn't care less about swordfights...!","TWN":"呃……！刀劍之爭什麼的無所謂……！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"어차피 내 전력은 가불기니까……!","JPN":"どうせ秋の全力はガード不能だもの……！","ENG":"You can't maintain guard against my attacks anyways...!","TWN":"反正我的全力攻擊是無法防禦的……！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"읏…? 검의 무게가……!?","JPN":"なっ……？　剣が……重くなっ……！？","ENG":"Ugh...? Why is your sword so heavy...?","TWN":"呃……？劍的重量……？！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"필살! 중량검 5000배!","JPN":"必殺！　重量剣5000倍！","ENG":"Here comes a fatal blow! Ultra Heavy Sword 5000x!","TWN":"必殺！重劍5000倍！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L45_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"하아아아아아아아아아……!","JPN":"はあああああああああ……！","ENG":"Haaaaaaaaah...!","TWN":"哈啊啊啊啊啊啊啊啊……！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L46_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"지금이라고! 이 재수없는 군바리 자식아아아아……!!","JPN":"今だ！　嫌味ったらしい軍人野郎うううう……！！","ENG":"Now! You insufferable GI...!","TWN":"就是現在！你這個倒楣的混蛋軍人……！！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"그으윽, 감히 이 몸을 지면으로 떨어트리다니! 이 불경한…… ","JPN":"ぐうっ、よくも余を地面に叩き落としてくれたな！　この不敬な……","ENG":"How dare you bring me down to the ground! You insolent...","TWN":"可惡，竟敢把我打倒在地！這個不敬的……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_MINISTRA_DAMAGE_DOWN"},{"id":"L50_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"음?","JPN":"……何？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"훌륭해. 베스트 포지션이었어, 레이디.","JPN":"素晴らしい。ベストポジションだったよ、レディー。","ENG":"Impressive. Flawless positioning, lady.","TWN":"太棒了，你的位置非常完美，女士。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그리고…….","JPN":"そして……","ENG":"And...","TWN":"然後……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"리벤지 매치는 인간의 승리다, 사도.","JPN":"リベンジマッチは人間の勝利だ、使徒。","ENG":"The revenge match ends in victory for humanity, Apostle.","TWN":"復仇之戰是人類勝利了，使徒。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_ELECTRIC"},{"id":"L6_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"아아, 아아아아아아……!","JPN":"ああ、ああああああ……！","ENG":"Ah, AAAAAAHHH...!","TWN":"啊啊……啊啊啊啊啊……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L10_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"후우, 해치웠나……?","JPN":"ふう、やったか……？","ENG":"Phew. Did we get rid of her...?","TWN":"呼，幹掉了嗎……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_ELECTRIC"},{"id":"L12_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"으아악!! 방금 들었어요, 히로세 씨!?","JPN":"うわああ！！　今の聞きました、廣瀬さん！？","ENG":"Aaah!! Ms. Hirose, did you hear that just now?","TWN":"嗚啊啊！！剛剛聽到了嗎，廣瀨秋？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"이 극악무도한 군바리가… 방금 부활 플래그를 세워버렸다고요……!","JPN":"この極悪非道な軍人野郎が……復活フラグを立てましたよ……！","ENG":"That ruthless GI... just foreshadowed her resurrection!","TWN":"這個窮凶極惡的軍人……剛剛立下了復活的flag……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"어서 일어나세요, 용사여! 이대로라면 사도가 부활할지도 몰라요!","JPN":"早く起き上がるのです、勇者よ！　このままでは使徒が復活するかも知れません！","ENG":"Get up, warrior! At this rate, the Apostle's gonna revive!","TWN":"快起來，勇士！這樣下去的話，魔神可能會復活的！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"히로세 씨……?","JPN":"廣瀬さん……？","ENG":"Ms. Hirose...?","TWN":"廣瀨秋……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L17_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"하하하… 지금 장난하는 거죠……?","JPN":"ははは……冗談ですよね……？","ENG":"Haha... This is a joke, right...?","TWN":"哈哈哈……這是開玩笑的吧……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"빨리 일어나서… 평소처럼 뭐라고 말 좀 해보라고요…….","JPN":"早く起きて、いつもみたいに何か言ってくださいよ……","ENG":"Come on, get up... Say something, like you always do...","TWN":"快起來……像平時一樣說點什麼吧……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"제발…….","JPN":"お願いだから……","ENG":"Please...","TWN":"拜託……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"예상외로군요. 이건 지금까지와는 다른 전개네요.","JPN":"予想外でした。今までとはまったく異なる展開ですね。","ENG":"This is unexpected. We're looking at a completely different outcome than before.","TWN":"出乎意料啊，這是和之前不同的展開呢。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"히로세 아키가 타기리온의 사도를 이렇게까지 궁지에 몰아넣을 줄이야.","JPN":"廣瀬秋がタギリオンの使徒をここまで追い詰めるとは。","ENG":"I never thought Hirose Aki would push Thagirion's Apostle this far.","TWN":"廣瀨秋竟然把塔基里翁的使徒逼到了這種地步。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"……당신은?","JPN":"……あんたは？","ENG":"...You are?","TWN":"……你是？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 사도는 불멸의 존재. 특별한 규칙이나 수단이 없다면, 완전히 소멸시킬 수 없습니다.","JPN":"しかし使徒とは不滅の存在。特別なルールや手段がない限り、完全に消滅させることはできません。","ENG":"But an Apostle is immortal. Without using a specific method or meeting a condition, they can't be truly destroyed.","TWN":"但是使徒是不朽的存在。如果沒有特殊的規則或手段，是無法徹底消滅的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"누구……?","JPN":"誰……？","ENG":"Who's that...?","TWN":"誰……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이거 놀랍군. 전장 한 가운데 느닷없이 당신 같은 미인이 나타나다니 말이야.","JPN":"これは驚いた。戦場のど真ん中に、いきなりあんたみたいな美人さんが現れるなんてな。","ENG":"Well now, this is a surprise. Didn't expect to see a beauty like you show up in the middle of a battlefield.","TWN":"這真是令人驚訝。在戰場的正中央，竟然突然出現了像你這樣的美人。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"민간인은 아니겠고, 관리국에서 보낸 카운터였으면 좋겠는데 말이지.","JPN":"民間人ではなさそうだし？　管理局から送られてきたカウンターであって欲しいとこだが？","ENG":"You're no civilian, that's for sure... I hope you're a Counter sent by the Administration.","TWN":"不是平民的話，希望是管理局派來的制裁者。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"관리국이라……. 그들은 오지 않아요.","JPN":"管理局ですか……彼らは来ません。","ENG":"The Administration... They're not coming.","TWN":"管理局……他們不會來的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"왜냐하면 제가 그렇게 각본을 짜두었으니까.","JPN":"なぜなら、私がそう脚本に書いていますから。","ENG":"Because I wrote the script that way.","TWN":"因為我已經寫好了劇本。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"각본이라고? 마치, 다 알고 있다는 듯이 말하는데?","JPN":"脚本？　は、まるで何もかもお見通しってような口ぶりだな。","ENG":"Script? You talk like you know how this all plays out.","TWN":"劇本？你說得好像全都知道一樣？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그래서? 관리국에서 보낸 지원군이 아니라면, 당신은 대체 누구지?","JPN":"それで？　管理局からの応援じゃないとしたら、あんたはいったい何者だ？","ENG":"So? If you're not backup from the Administration, then who are you?","TWN":"所以呢？如果你不是管理局派來的援軍，那你到底是誰？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"글쎄요, 저에게는 많은 가면들이 있지만…….","JPN":"どうでしょう、私には様々な仮面がありますが……","ENG":"Well... I wear quite a few masks, you see...","TWN":"嗯，我有很多面具……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"지금은… 그래요, 아마도 당신이 짐작하고 있는 바가 맞을 겁니다, 제이크 워커 대령.","JPN":"今は……そうですね。おそらくあなたが思っているそれで合っていますよ、ジェイク・ウォーカー大佐。","ENG":"But for now... yes, Colonel Jake Walker, I think you've guessed correctly.","TWN":"現在……是的，或許你猜得沒錯，傑克·沃克上校。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저는 당신들의 세계를 으스러트릴 각오로 이 무대 위에 섰으니까요.","JPN":"私はあなたたちの世界を潰す覚悟でこの舞台に立っていますので。","ENG":"I've stepped onto this stage fully prepared to shatter your entire world.","TWN":"我站在這個舞台上，是為了粉碎你們的世界。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……암군의 사도로서.","JPN":"……暗君の使徒として。","ENG":"...As the Apostle of the Ignorant Monarch.","TWN":"……作為暗軍的使徒。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"카일은......? 어떻게 됐지?","JPN":"カイルは……？　どうなったんだ？","ENG":"Kyle... Where is he?","TWN":"凱爾呢？他怎麼樣了？"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......전사했습니다.","JPN":"……戦死しました。","ENG":"He's... dead.","TWN":"……戰死了。"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"실비아는......?","JPN":"シルビアは……？","ENG":"What about Sylvia?","TWN":"希爾維亞呢？"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......전사했습니다.","JPN":"……戦死しました。","ENG":"She's dead, too.","TWN":"……戰死了。"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그래도 우리측 최강의 카드인 제이크 대령이 버티고 있으니까 쉽게 뚫리지는 않을 겁니다.","JPN":"ですが、味方の中で最強のジェイク大佐がいるので、\\n簡単には突破できないはずです。","ENG":"But we've still got Colonel Jake, the ace up our sleeve. He won't let them pass easily.","TWN":"不過我們這邊還有最強王牌——傑克大校頂著，沒有那麼容易被突破。"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"이 정도로 잠재력이 높을 줄 알았다면 신병 시절부터 더 험하게 굴릴 걸 그랬군요, 하하.","JPN":"こんなにも潜在能力が高いと知ってたら、新米の頃からもっと鍛えてやれば良かった、ハハハ。","ENG":"If I knew he'd be so useful, I would have drilled him harder when he was a recruit. Hah hah.","TWN":"早知道他這麼有潛力，我就該在他當新兵的時候，操他操得兇一點了，哈哈。"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......정신을 차리셨으니 일단 지하통로로 가시죠.","JPN":"……意識が戻られたので、いったん地下通路へ移動しましょう。","ENG":"Now that you're awake, you should head out to the underground passageway.","TWN":"……既然您已經清醒了，總之先去地下通道吧。"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"운이 좋으면 아직 인근 벙커로 피신할 수 있을 겁니다.","JPN":"運が良ければ、まだ近隣のバンカーへ避難できると思います。","ENG":"If you're lucky, you can get to the nearby bunker without incident.","TWN":"運氣好的話，還可以在附近的掩體避難。"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......아니, 가지 않겠네.","JPN":"……いや、やめておく。","ENG":"No, I'm not going.","TWN":"……不，我就不去了。"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"사령관님?","JPN":"司令官？","ENG":"Commander?","TWN":"司令官？"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"나도 늙은 모양이야.","JPN":"私も年をとったみたいだ。","ENG":"I'm getting old.","TWN":"我也上年紀了。"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"진작 결정을 내렸어야 했는데...... 아마 무서웠나 보지.","JPN":"もっと早く決断すべきだったのに……臆病になっていたようだ。","ENG":"I should have made up my mind earlier, but... I was probably too scared.","TWN":"明明該儘早下定決心的……我大概是在害怕吧。"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"무슨 말씀을 하시는 겁니까?","JPN":"どういう意味でしょうか？","ENG":"What are you talking about?","TWN":"您在說什麼？"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"자네가 준비하던 그 계획...... 마지막 실험체가 필요하다고 했었지?","JPN":"君が準備していたあの計画……\\n最後の実験体が必要だと言っていたな？","ENG":"That plan of yours. You said you need one more test subject to realize it.","TWN":"你準備的那個計畫……說是需要最後的實驗體對吧？"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"안 됩니다!!","JPN":"それはダメです！！","ENG":"No!","TWN":"不行！！"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"어차피 이 몸으로는 더 싸울 수도 없어......","JPN":"どうせこの体ではこれ以上戦えない……","ENG":"My body can't handle any more fighting.","TWN":"反正這副身軀也無法再戰鬥了……"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그렇다면...... 차라리 실험체로 사용하는 게 인류를 위한 일이겠지.","JPN":"だったら……\\nいっそのこと実験体にしたほうが、人類に貢献できるだろう。","ENG":"But it still can contribute to the test for mankind.","TWN":"這樣的話……那還不如當成實驗體，這樣才對人類有貢獻吧。"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"테라사이드 프로젝트는 아직 완성되지 않았습니다!","JPN":"テラサイド・プロジェクトはまだ完成されていません！　","ENG":"Project Terraside is not complete!","TWN":"特拉賽德計畫還沒有完成！"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"설사 사령관님의 육체를 사용한다고 해도 남은 인류를 구할 거란 보장은......","JPN":"たとえ司令官の体を借りたとしても、\\n残りの人類を救えるという保証はどこにも……","ENG":"Even with your help, there's no guarantee that it can save the remaining population.","TWN":"就算使用了司令官大人的身體，也無法保證可以救出剩下的人類……"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"괜찮아......","JPN":"いいんだ……","ENG":"I know, and I'm fine with that.","TWN":"沒關係……"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"괜찮아, 도미닉. 자네 혼자 모든 책임을 지려고 애쓸 필요는 없어.","JPN":"いいんだ、ドミニーク。君ひとりで全責任を負う必要はないんだよ。","ENG":"It's okay, Dominic. You don't have to be responsible for everything.","TWN":"沒關係的，多明尼克。你沒必要這麼拼命地，把責任都攬到自己身上。"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"사람은 할 수 있는 데까지만 하면 되는 거야.","JPN":"できるとこまでやればいいんだ。","ENG":"Let's just do the best we can,","TWN":"人只要做到自己力所能及的事就行了。"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"나머지는...... 다음 번 인류에게 맡기면 되겠지.","JPN":"残りは……次の人類に任せるでいいだろう。","ENG":"and leave the rest to the next ones.","TWN":"剩下的……就交給下一代吧。"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"우리에게 유산을 물려준 이들이 그러했듯이.","JPN":"我々に遺産を残した先祖のようにな。","ENG":"Just like our predecessors did.","TWN":"就像那些把遺物留給我們的人一樣。"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"이럴 줄 알았으면 조금 더 일찍 관리국과 합작을 할 걸 그랬군요. 그랬다면......","JPN":"こうなるとわかってたら、もっと早く管理局と手を組んだのに。\\nそうしていれば……","ENG":"If I knew better, I would have collaborated with the Administration earlier. And if I did...","TWN":"早知如此，我就應該更早一些和管理局合作的。這樣的話……"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그들을 너무 믿지 말게나, 도미닉......","JPN":"連中のことをあまり信頼しすぎないほうが良い、ドミニーク……","ENG":"Don't trust it too much, Dominic.","TWN":"不要太相信他們了，多明尼克。"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"분명 그들도 인류를 위해서 싸우고는 있지만......","JPN":"彼らも人類のために戦ってはいるが……","ENG":"Sure, it's fighting for humanity just like us,","TWN":"雖然他們看起來確實是在為人類而戰……"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"어쩐지 내 직감엔 그들의 목적은 엄연히 다른 곳에 있는 것 같다고 느껴지는군.","JPN":"私の直感では、彼らの目的が別のところにある気がする……","ENG":"but I have a feeling that it also has a hidden agenda.","TWN":"但我的直覺告訴我，他們另有目的。"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이제 눈이 침침해지는군.","JPN":"そろそろ目が霞んできたな。","ENG":"Now, my eyes are blurry.","TWN":"現在，我的視線開始模糊了。"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"날 좀 옮겨주게...... 그럴 수 있겠지?","JPN":"私を運んでくれ……いいな？","ENG":"Could you help me move?","TWN":"幫我挪一下……可以嗎？"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......알겠습니다.","JPN":"……わかりました。","ENG":"Yes, ma'am.","TWN":"……知道了。"},"stage":{"bg":"SS_DELTA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"크윽! 뭐야, 이 진동은……!?","JPN":"くっ！　何、この揺れ……！？","ENG":"Ugh! What's with this shaking...?!","TWN":"呃！這，這震動是怎麼回事……！"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"설마, 벌써 이곳 본부가 녀석들에게 공격받고 있는 건가……?","JPN":"まさか、もうこの本部にまでやつらの攻撃が……？","ENG":"Is the enemy already hitting HQ...?","TWN":"難道，本部已經被那些傢伙攻擊了嗎……？"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"……아니야.","JPN":"……違う。","ENG":"...No.","TWN":"……不是的。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"이건 건물 밖에서부터 들려오는 소리가 아니야… 울림이 달라…….","JPN":"これは建物の外から聞こえる音じゃない……響きが違う……","ENG":"That sound isn't coming from outside... The vibration feels different...","TWN":"這不是從建築外面傳來的聲音……回聲不一樣……"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"틀림없이 아래에서… 지하로부터 들려오는 소리야……!","JPN":"この音は下から……地下からだ……！","ENG":"It's definitely coming from below... from underground...!","TWN":"一定是從下面……從地下傳來的聲音……！"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"그렇다면… 지하에서 침식체가……?","JPN":"ということは……地下に侵食体が……？","ENG":"Then that means... there's a C.O. down there...?","TWN":"那麼……地下有侵蝕體……？"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"제기랄! 이러다가 무너지겠어!","JPN":"クソ！　このままじゃ崩れる！","ENG":"Damn it! At this rate, the whole place is gonna collapse!","TWN":"可惡！這樣下去會崩潰的！"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"뭐가 어떻게 돌아가는 거야! 일단 여기서 나가자!","JPN":"もう、何がどうなってんの！　とりあえずここから出なきゃ！","ENG":"What is going on?! Gonna have to get out of here!","TWN":"到底是怎麼回事！先從這裡出去吧！"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"하아, 하아, 하아……!","JPN":"はぁ、はぁ、はぁ……！","ENG":"*Huff* *Huff* *Huff…!*","TWN":"哈啊，哈啊，哈啊……！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"제길, 부상 때문에 호흡이……","JPN":"くそ、傷のせいで息が……","ENG":"Shucks, I can't breathe right with this injury…","TWN":"該死，受傷導致呼吸……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"음?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"저건 또 뭐야……?","JPN":"あれは何……？","ENG":"What on earth is that...?","TWN":"那又是什麼……？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"본부 건물을 부수고… 그 안에서 침식체가……?","JPN":"本部を壊して……その奥から侵食体が……？","ENG":"It destroyed the HQ building and... Isn't that a C.O. inside...?","TWN":"破壞總部大樓……然後從裡面出現侵蝕體……？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"천사……. 지금까지 한 번도 본 적 없는 침식체야…….","JPN":"天使……今まで一度も見たことない侵食体だ……","ENG":"An angel...? I've never seen a C.O. like that before...","TWN":"天使……至今為止從未見過的侵蝕體……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"이 군바리 자식들… 지금까지 기지에 짱 박혀서 저런 걸 만들고 있었던 거야……?","JPN":"あの軍人どもめ……今まで基地に篭ってあんなもの作ってたの……？","ENG":"Those damn GIs... So this is what they've been hiding away in the base all this time...?","TWN":"這些軍人……到現在為止一直躲在基地裡製作這種東西嗎……？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"도대체 무슨 짓을 저지른 거야…….","JPN":"いったい何しでかしたんだ……","ENG":"What the hell have they done...?","TWN":"你到底幹了什麼……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"지금부터 무슨 일이 일어나는 거냐고……!!","JPN":"今から何が起きるっていうんだよ……！！","ENG":"What's going to happen now...?!","TWN":"之後到底會發生什麼事啊……！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 것은 각본대로.","JPN":"すべては脚本どおりに。","ENG":"Everything according to the script.","TWN":"一切都在劇本之中。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저것이 테라사이드 프로젝트의 결과물…….","JPN":"あれがテラサイドプロジェクトの成果……","ENG":"They are the result of the Terraside Project…","TWN":"那就是特拉賽德計畫的成果……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 저들의 <color=#ffd34c>최종 변이 인자</color>는 신성의 찌꺼기에 불과해.","JPN":"しかし彼らの<color=#ffd34c>最終変異ファクター</color>は、所詮神聖の残りかすに過ぎない。","ENG":"But their <color=#ffd34c>Ultimate Mutation Factor</color> is nothing more than a residue of the Divinity.","TWN":"但是他們的<color=#ffd34c>最後變異因數</color>不過是神聖的殘渣。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"결국, 인간의 몸으로 그 찌꺼기를 이식해봤자, 그 말로는 추악한 침식체로 전락할 뿐인가?","JPN":"結局、人間の身にその残りかすを移植したところで、最後は醜い侵食体への転落か。","ENG":"In the end, it seems that transplanting that residue into a human body only leads to one thing... turning into a grotesque C.O.","TWN":"最後，即使將那殘渣移植到人類身上，結果也只會墮落成醜陋的侵蝕體嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"물론, 저들은 그조차 인류 존속을 위한 희망이라고 생각하겠지만…….","JPN":"もちろん、彼らはそれすらも人類存続のための希望と思うのだろうけど……","ENG":"Of course, they probably still see it as humanity's last hope.","TWN":"當然，他們甚至認為那是人類生存的希望……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그럼에도 변수 같은 건 없었어.","JPN":"それでも変数なんてものはなかった。","ENG":"Nothing changed. No variables.","TWN":"儘管如此，也並沒有改變什麼。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"결국… 이 세계에도 천사 같은 건 나타나지 않았어…….","JPN":"結局……この世界にも天使なんて現れなかった……","ENG":"In the end... no angel appeared in this world either.","TWN":"最後……這個世界上也沒有出現天使……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};